import{_ as t,a,b as o,c as l}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as i,o as s,c as n,a2 as r}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Добавление канала Google Drive","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/upload/google-drive.md","filePath":"ru-RU/upload/google-drive.md","lastUpdated":1781962217000}'),d={name:"ru-RU/upload/google-drive.md"};function c(p,e,h,g,u,b){return s(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="добавление-канала-google-drive" tabindex="-1">Добавление канала Google Drive <a class="header-anchor" href="#добавление-канала-google-drive" aria-label="Permalink to &quot;Добавление канала Google Drive&quot;">​</a></h1><h2 id="что-подготовить-сначала" tabindex="-1">Что подготовить сначала <a class="header-anchor" href="#что-подготовить-сначала" aria-label="Permalink to &quot;Что подготовить сначала&quot;">​</a></h2><p>Перед началом подготовьте:</p><table tabindex="0"><thead><tr><th>Что нужно</th><th>Зачем это нужно</th></tr></thead><tbody><tr><td>Аккаунт Google</td><td>Для доступа к Google Cloud и авторизации Google Drive</td></tr><tr><td>Проект Google Cloud</td><td>Для включения Drive API и создания OAuth credentials</td></tr><tr><td>OAuth 2.0 client</td><td>ImgBed использует его для получения <code>Client ID</code>, <code>Client Secret</code> и <code>Refresh Token</code></td></tr><tr><td>Ваш домен ImgBed</td><td>Для OAuth redirect URI. Он должен совпадать с доменом, который вы реально используете.</td></tr></tbody></table><h2 id="настроика" tabindex="-1">Настройка <a class="header-anchor" href="#настроика" aria-label="Permalink to &quot;Настройка&quot;">​</a></h2><h3 id="шаг-1-включите-google-drive-api" tabindex="-1">Шаг 1. Включите Google Drive API <a class="header-anchor" href="#шаг-1-включите-google-drive-api" aria-label="Permalink to &quot;Шаг 1. Включите Google Drive API&quot;">​</a></h3><ol><li>Откройте Google Cloud Console.</li><li>Создайте новый проект или выберите существующий.</li><li>Перейдите в <code>APIs &amp; Services</code>.</li><li>Нажмите <code>Enable APIs and Services</code>.</li><li>Найдите <code>Google Drive API</code>.</li><li>Откройте его и нажмите enable.</li></ol><h3 id="шаг-2-настроите-oauth-consent-screen" tabindex="-1">Шаг 2. Настройте OAuth Consent Screen <a class="header-anchor" href="#шаг-2-настроите-oauth-consent-screen" aria-label="Permalink to &quot;Шаг 2. Настройте OAuth Consent Screen&quot;">​</a></h3><ol><li>В Google Cloud откройте <code>Google Auth Platform</code>.</li><li>Заполните базовую информацию <code>Branding</code>: имя app, support email и developer contact email.</li><li>Откройте <code>Audience</code>.</li><li>Для большинства личных self-hosted развертываний выберите <code>External</code>.</li><li>Если выбран <code>External</code>, добавьте Google-аккаунт, который хотите авторизовать, в <code>Test users</code>.</li><li>Откройте <code>Data Access</code>.</li><li>Добавьте нужные permissions для Google Drive.</li></ol><h3 id="шаг-3-создаите-oauth-2-0-client" tabindex="-1">Шаг 3. Создайте OAuth 2.0 Client <a class="header-anchor" href="#шаг-3-создаите-oauth-2-0-client" aria-label="Permalink to &quot;Шаг 3. Создайте OAuth 2.0 Client&quot;">​</a></h3><ol><li>В <code>Google Auth Platform</code> откройте <code>Clients</code>.</li><li>Создайте новый client.</li><li>Установите application type как <code>Web application</code>.</li><li>Дайте client понятное имя.</li><li>Для authorized JavaScript origins введите URL ImgBed, например:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>Для authorized redirect URIs введите:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+t+'" alt="Создание OAuth client" loading="lazy"></p><p><img src="'+a+'" alt="Ввод домена и callback URL" loading="lazy"></p><p>После создания client скопируйте:</p><table tabindex="0"><thead><tr><th>Сгенерированное значение</th><th>Поле ImgBed</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="шаг-4-заполните-канал-google-drive" tabindex="-1">Шаг 4. Заполните канал Google Drive <a class="header-anchor" href="#шаг-4-заполните-канал-google-drive" aria-label="Permalink to &quot;Шаг 4. Заполните канал Google Drive&quot;">​</a></h2><p>В настройках загрузки выберите <code>Google Drive</code> и заполните:</p><table tabindex="0"><thead><tr><th>Поле ImgBed</th><th>Что ввести</th></tr></thead><tbody><tr><td>Channel name</td><td>Понятное имя, например <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Client ID из Google Cloud</td></tr><tr><td>Client Secret</td><td>Client Secret из Google Cloud</td></tr><tr><td>Refresh Token</td><td>Пока оставьте пустым. Получите его на следующем шаге.</td></tr><tr><td>Root directory</td><td>Необязательно. По умолчанию <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+o+'" alt="Вставка client details в ImgBed" loading="lazy"></p><h2 id="шаг-5-получите-refresh-token" tabindex="-1">Шаг 5. Получите Refresh Token <a class="header-anchor" href="#шаг-5-получите-refresh-token" aria-label="Permalink to &quot;Шаг 5. Получите Refresh Token&quot;">​</a></h2><ol><li>Нажмите <code>Get Token</code>.</li><li>Выберите Google-аккаунт, который хотите подключить.</li><li>Пройдите подсказки авторизации.</li><li>На callback-странице появится <code>Refresh Token</code>.</li><li>Скопируйте его.</li><li>Вернитесь в ImgBed и вставьте его в поле <code>Refresh Token</code>.</li></ol><p><img src="'+l+`" alt="Копирование Refresh Token после авторизации" loading="lazy"></p><p>Если позже вы смените Google-аккаунт, OAuth client или старая авторизация истечет, удалять канал не нужно. Откройте страницу редактирования и нажмите <code>Reauthorize</code>.</p><h2 id="шаг-6-сохраните-канал" tabindex="-1">Шаг 6. Сохраните канал <a class="header-anchor" href="#шаг-6-сохраните-канал" aria-label="Permalink to &quot;Шаг 6. Сохраните канал&quot;">​</a></h2><p>Когда все поля заполнены, сохраните канал.</p><h2 id="короткии-сценарии" tabindex="-1">Короткий сценарий <a class="header-anchor" href="#короткии-сценарии" aria-label="Permalink to &quot;Короткий сценарий&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Открыть Google Cloud</span></span>
<span class="line"><span>-&gt; Создать или выбрать проект</span></span>
<span class="line"><span>-&gt; Включить Google Drive API</span></span>
<span class="line"><span>-&gt; Настроить Google Auth Platform</span></span>
<span class="line"><span>-&gt; Если Audience = External, добавить свой Google-аккаунт в Test users</span></span>
<span class="line"><span>-&gt; Создать Web application OAuth client</span></span>
<span class="line"><span>-&gt; Использовать https://your-domain.com/api/oauth/google/callback как redirect URI</span></span>
<span class="line"><span>-&gt; Ввести Client ID и Client Secret в ImgBed</span></span>
<span class="line"><span>-&gt; Нажать Get Token</span></span>
<span class="line"><span>-&gt; Войти через Google и авторизовать</span></span>
<span class="line"><span>-&gt; Скопировать Refresh Token с callback-страницы</span></span>
<span class="line"><span>-&gt; Вставить его обратно в ImgBed и сохранить</span></span>
<span class="line"><span>-&gt; Загрузить тестовое изображение</span></span></code></pre></div><h2 id="ссылки" tabindex="-1">Ссылки <a class="header-anchor" href="#ссылки" aria-label="Permalink to &quot;Ссылки&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const f=i(d,[["render",c]]);export{k as __pageData,f as default};
